parameters.jsCode:
const item = $json.output?.[0]?.content?.[0];

if (!item) {
  throw new Error('No model output found');
}

if (item.type === 'refusal') {
  throw new Error(`Model refused request: ${item.refusal}`);
}

let parsed;
if (item.parsed) {
  parsed = item.parsed;
} else if (item.text) {
  parsed = JSON.parse(item.text);
} else {
  throw new Error('No parsable JSON returned');
}

return [{ json: parsed }];
